class Solution:
    def flipZeroCount(self, nums: List[int]) -> int:
        return sum(1 for num in nums if num == 1)

if __name__ == '__main__':
    from sys import stdin
    nums = list(map(int, stdin.readline().split()))
    print(Solution().flipZeroCount(nums))

