class Solution {
public:
    int flipZeroCount(vector<int>& nums) {
        return count_if(nums.begin(), nums.end(), [](int x) { return x == 1; });
    }
};

int main() {
    vector<int> nums = {1, 1, 0};
    Solution solution;
    cout << solution.flipZeroCount(nums) << endl;
    return 0;
}
